/// Number of entries in the Catmull-Rom weight LUT.
pub(crate) const WN: usize = 1024;
/// Bit-shift for weight scale: weights are at 2^30.
pub(crate) const WS: u32 = 30;
/// Divisor to map remainder → weight index: RANGE / WN.
pub(crate) const FRAC_DIVISOR: i64 = RANGE_I64 / WN as i64;

/// Precomputed Catmull-Rom basis weights at 2^30.
///
/// `CR_W[k] = [w0, w1, w2, w3]` for `t = k / WN`.
/// With WN=1024 and WS=30, the step is 2^20, and all intermediate
/// products (t², t³) are exact — zero truncation error.
/// Max |w_i| < 1.5 × 2^30. Product w_i × p_i (p at SCALE_6) < 1.6e15, fits i64.
pub(crate) const CR_W: [[i32; 4]; WN] = {
    let mut out = [[0i32; 4]; WN];
    let s: i64 = 1 << WS;
    let mut k = 0usize;
    while k < WN {
        let t = (k as i64) << (WS - 10); // k * 2^20, exact
        let t2 = t * t >> WS;
        let t3 = t2 * t >> WS;
        out[k][0] = ((-t + 2 * t2 - t3) / 2) as i32;
        out[k][1] = ((2 * s - 5 * t2 + 3 * t3) / 2) as i32;
        out[k][2] = ((t + 4 * t2 - 3 * t3) / 2) as i32;
        out[k][3] = ((-t2 + t3) / 2) as i32;
        k += 1;
    }
    out
};

/// Catmull-Rom via weight-LUT dot product. No divides.
///
/// `w` is the 4-weight row from `CR_W`. `p0..p3` at SCALE_6. Result at SCALE_6.
#[inline(always)]
pub(crate) fn cr_dot(w: &[i32; 4], p0: i64, p1: i64, p2: i64, p3: i64) -> i64 {
    (w[0] as i64 * p0 + w[1] as i64 * p1 + w[2] as i64 * p2 + w[3] as i64 * p3) >> WS
}

/// Fast bivariate normal CDF via const Φ₂ table with weight-LUT bicubic.
///
/// Fast bivariate normal CDF at precomputed fixed `ρ` via Catmull-Rom
/// bicubic interpolation on a 64×64 lookup table.
///
/// Computes `P(X ≤ a, Y ≤ b)` where `(X, Y) ~ N(0, 0, 1, 1, ρ)`.
///
/// # Arguments
///
/// * `a`, `b` — signed fixed-point `i128` at `SCALE` (1e12).
/// * `table` — the precomputed Φ₂ table (use `PHI2_*` constants).
///
/// # Domain
///
/// `a`, `b` ∈ `[-4·SCALE, 4·SCALE]`. Values outside are clamped.
///
/// # Accuracy
///
/// Max absolute error < 9.0×10⁻⁵ (validated across 630K vectors).
///
/// # CU cost
///
/// ~943 CU on SBF. Pure i64 arithmetic — no `norm_cdf`, no i128 in the
/// hot path.
///
/// # Errors
///
/// Returns `Ok` for all valid inputs. Cannot fail in practice — the
/// `Result` wrapper is for API consistency with the `bvn_cdf` family.
/// Infallible Φ₂(a,b;ρ) at SCALE_6 in pure i64. Inputs/indices clamped — cannot fail.
#[inline(always)]
pub fn bvn_cdf_i64(a: i64, b: i64, table: &[[i32; N]; N]) -> i64 {
    let a64 = a.clamp(DOMAIN_MIN_I64, DOMAIN_MAX_I64);
    let b64 = b.clamp(DOMAIN_MIN_I64, DOMAIN_MAX_I64);
    let a_off = a64 - DOMAIN_MIN_I64;
    let b_off = b64 - DOMAIN_MIN_I64;
    let ia_scaled = a_off * N_MINUS_1;
    let i0 = (ia_scaled / RANGE_I64).min(N as i64 - 2) as i32;
    let ib_scaled = b_off * N_MINUS_1;
    let j0 = (ib_scaled / RANGE_I64).min(N as i64 - 2) as i32;
    let wi_a = ((ia_scaled % RANGE_I64) / FRAC_DIVISOR) as usize;
    let wi_b = ((ib_scaled % RANGE_I64) / FRAC_DIVISOR) as usize;
    let wa = &CR_W[if wi_a < WN { wi_a } else { WN - 1 }];
    let wb = &CR_W[if wi_b < WN { wi_b } else { WN - 1 }];
    let n = N as i32;
    let mut cols = [0i64; 4];
    for di in 0..4i32 {
        let ii = (i0 - 1 + di).clamp(0, n - 1) as usize;
        let p0 = table[ii][(j0 - 1).clamp(0, n - 1) as usize] as i64;
        let p1 = table[ii][j0.clamp(0, n - 1) as usize] as i64;
        let p2 = table[ii][(j0 + 1).clamp(0, n - 1) as usize] as i64;
        let p3 = table[ii][(j0 + 2).clamp(0, n - 1) as usize] as i64;
        cols[di as usize] = cr_dot(wb, p0, p1, p2, p3);
    }
    cr_dot(wa, cols[0], cols[1], cols[2], cols[3]).clamp(0, S6)
}

#[inline(always)]
pub fn bvn_cdf_phi2table(a: i128, b: i128, table: &[[i32; N]; N]) -> Result<i128, SolMathError> {
    let a64 = (a.clamp(DOMAIN_MIN_I64 as i128, DOMAIN_MAX_I64 as i128)) as i64;
    let b64 = (b.clamp(DOMAIN_MIN_I64 as i128, DOMAIN_MAX_I64 as i128)) as i64;
    Ok(bvn_cdf_i64(a64, b64, table) as i128 * SHIFT as i128)
}

// (Fritsch-Carlson monotone Hermite path removed — slopes no longer needed.)
// (Fritsch-Carlson monotone Hermite code removed — slopes no longer shipped.)

#[cfg(test)]
mod tests {
    extern crate std;

    use super::*;

    fn phi_f64(x: f64) -> f64 {
        0.398_942_280_401_432_7 * (-0.5 * x * x).exp()
    }
    fn std_norm_cdf_ref(x: f64) -> f64 {
        if x < -10.0 {
            return 0.0;
        }
        if x > 10.0 {
            return 1.0;
        }
        let n = 4_096usize;
        let left = -10.0f64;
        let h = (x - left) / n as f64;
        let mut sum = phi_f64(left) + phi_f64(x);
        for i in 1..n {
            let xi = left + h * i as f64;
            sum += if i % 2 == 0 {
                2.0 * phi_f64(xi)
            } else {
                4.0 * phi_f64(xi)
            };
        }
        (sum * h / 3.0).clamp(0.0, 1.0)
    }
    fn bvn_cdf_ref(x: f64, y: f64, rho: f64) -> f64 {
        if rho >= 0.999_999 {
            return std_norm_cdf_ref(x.min(y));
        }
        if x > 0.0 && y > 0.0 {
            return (std_norm_cdf_ref(x) + std_norm_cdf_ref(y) - 1.0 + bvn_cdf_ref(-x, -y, rho))
                .clamp(0.0, 1.0);
        }
        if x > 0.0 {
            return (std_norm_cdf_ref(y) - bvn_cdf_ref(-x, y, -rho)).clamp(0.0, 1.0);
        }
        if y > 0.0 {
            return (std_norm_cdf_ref(x) - bvn_cdf_ref(x, -y, -rho)).clamp(0.0, 1.0);
        }
        let alpha = rho.asin();
        let base = std_norm_cdf_ref(x) * std_norm_cdf_ref(y);
        let n = 4_096usize;
        let h = alpha / n as f64;
        let mut sum = 1.0
            + (-(x * x - 2.0 * x * y * alpha.sin() + y * y) / (2.0 * alpha.cos().powi(2))).exp();
        for i in 1..n {
            let theta = h * i as f64;
            let exp =
                (-(x * x - 2.0 * x * y * theta.sin() + y * y) / (2.0 * theta.cos().powi(2))).exp();
            sum += if i % 2 == 0 { 2.0 * exp } else { 4.0 * exp };
        }
        (base + sum * h / 3.0 / (2.0 * core::f64::consts::PI)).clamp(0.0, 1.0)
    }

    fn test_phi2_vs_f64(table: &[[i32; N]; N], rho: f64, label: &str) {
        let mut state = 0xCAFE_BABE_DEAD_BEEFu64;
        let mut max_err = 0.0f64;
        for _ in 0..4_096 {
            state = state
                .wrapping_mul(6_364_136_223_846_793_005)
                .wrapping_add(1);
            let x = (((state >> 11) % 8_001) as i64 - 4_000) as f64 / 1_000.0;
            state = state
                .wrapping_mul(6_364_136_223_846_793_005)
                .wrapping_add(1);
            let y = (((state >> 9) % 8_001) as i64 - 4_000) as f64 / 1_000.0;
            let a_fp = (x * SCALE_I as f64).round() as i128;
            let b_fp = (y * SCALE_I as f64).round() as i128;
            let fast = bvn_cdf_phi2table(a_fp, b_fp, table).expect("phi2") as f64 / SCALE_I as f64;
            let want = bvn_cdf_ref(x, y, rho);
            let err = (fast - want).abs();
            if err > max_err {
                max_err = err;
            }
        }
        assert!(max_err < 1.0e-4, "{label}: max_err={max_err:.2e}");
    }

    #[test]
    fn phi2_iwm_qqq() {
        test_phi2_vs_f64(&PHI2_IWM_QQQ, 0.7763218317079643, "IWM_QQQ");
    }
    #[test]
    fn phi2_iwm_spy() {
        test_phi2_vs_f64(&PHI2_IWM_SPY, 0.8635323683789009, "IWM_SPY");
    }
    #[test]
    fn phi2_qqq_spy() {
        test_phi2_vs_f64(&PHI2_QQQ_SPY, 0.8989418379506557, "QQQ_SPY");
    }

    #[test]
    fn phi2_boundary() {
        for table in [&PHI2_IWM_QQQ, &PHI2_QQQ_SPY] {
            let lo = bvn_cdf_phi2table(-4 * SCALE_I, -4 * SCALE_I, table).unwrap();
            assert!(lo >= 0 && lo < SCALE_I / 100);
            let hi = bvn_cdf_phi2table(4 * SCALE_I, 4 * SCALE_I, table).unwrap();
            assert!(hi > SCALE_I * 99 / 100 && hi <= SCALE_I);
        }
    }
}
